"use client"

import { useState, useEffect, useCallback, useMemo } from "react"
import { supabase } from "@/lib/supabase"
import { getOwnerStatsAction, getInventoryCriticalAction, type BusinessMetrics } from "@/lib/actions/dashboard.actions"
import { updateProductAction, deleteProductAction } from "@/lib/actions/product.actions"
import { Card } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Badge } from "@/components/ui/badge"
import {
  ArrowLeft, AlertTriangle, TrendingUp, Package, Plus,
  Loader2, DollarSign, Calendar as CalendarIcon, Eye, Clock,
  Pencil, Trash2, History, Users, Sparkles, Briefcase, Receipt, QrCode, MapPin, Settings
} from "lucide-react"
import CrearProducto from "@/components/crear-producto"
import { cn } from "@/lib/utils"
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover"
import { Calendar } from "@/components/ui/calendar"
import { DateRange } from "react-day-picker"
import { format, subDays, startOfDay, endOfDay, parseISO } from "date-fns"
import { es } from "date-fns/locale"
import { toast } from "sonner"
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog"
import GestionProveedores from "@/components/gestion-proveedores"
import ControlSaldoProveedor from "@/components/control-saldo-proveedor"
import { InvitarEmpleado } from "@/components/invitar-empleado"
import { generarTicketPDF } from "@/lib/generar-ticket"
import TeamRanking from "@/components/team-ranking"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import GestionSucursales from "@/components/gestion-sucursales"
import GenerarQRFichaje from "@/components/generar-qr-fichaje"
import { CapitalBadges } from "@/components/capital-badges"

// Importar componentes de tabs extraídos
import { TabAlerts, TabInventory, TabSales, TabFinance, TabSupervision } from "@/components/dashboard"

// Importar tipos centralizados
import type {
  DashboardTab, MetricaStock, ProductoDashboard, HistorialPrecio,
  VentaJoin, VentaServicio, PaymentBreakdown, TurnoAudit, AsistenciaRecord
} from "@/types/dashboard.types"

const UMBRAL_STOCK_BAJO = 5

interface DashboardDuenoProps {
  onBack: () => void
  sucursalId: string
}

export default function DashboardDueno({ onBack, sucursalId }: DashboardDuenoProps) {
  // ─────────────────────────────────────────────────────────────────────────────
  // ESTADO: Contexto de organización
  // ─────────────────────────────────────────────────────────────────────────────
  const [currentSucursalId, setCurrentSucursalId] = useState(sucursalId)
  const [organizationId, setOrganizationId] = useState<string>("")
  const [sucursales, setSucursales] = useState<{id: string, nombre: string}[]>([])

  // ─────────────────────────────────────────────────────────────────────────────
  // ESTADO: UI y navegación
  // ─────────────────────────────────────────────────────────────────────────────
  const [activeTab, setActiveTab] = useState<DashboardTab>("sales")
  const [searchQuery, setSearchQuery] = useState("")
  const [loading, setLoading] = useState(false)
  const [dateRange, setDateRange] = useState<DateRange | undefined>({
    from: startOfDay(subDays(new Date(), 7)),
    to: endOfDay(new Date()),
  })

  // ─────────────────────────────────────────────────────────────────────────────
  // ESTADO: Datos del dashboard
  // ─────────────────────────────────────────────────────────────────────────────
  const [productos, setProductos] = useState<ProductoDashboard[]>([])
  const [capitalEnRiesgo, setCapitalEnRiesgo] = useState<MetricaStock>({ capital: 0, unidades: 0, criticos: [] })
  const [ventasRecientes, setVentasRecientes] = useState<VentaJoin[]>([])
  const [totalVendido, setTotalVendido] = useState(0)
  const [paymentBreakdown, setPaymentBreakdown] = useState<PaymentBreakdown>({
    cash: 0, card: 0, transfer: 0, wallet: 0
  })
  const [ventasServicios, setVentasServicios] = useState<VentaServicio[]>([])
  const [totalServiciosVendido, setTotalServiciosVendido] = useState(0)
  const [paymentBreakdownServicios, setPaymentBreakdownServicios] = useState<PaymentBreakdown>({
    cash: 0, card: 0, transfer: 0, wallet: 0
  })
  const [turnosAudit, setTurnosAudit] = useState<TurnoAudit[]>([])
  const [asistencias, setAsistencias] = useState<AsistenciaRecord[]>([])
  const [biMetrics, setBiMetrics] = useState<BusinessMetrics>({
    gross: 0, net: 0, margin: 0, traceable: 0, cash: 0, ROI: 0
  })

  // ─────────────────────────────────────────────────────────────────────────────
  // ESTADO: Modales y acciones
  // ─────────────────────────────────────────────────────────────────────────────
  const [editingProduct, setEditingProduct] = useState<ProductoDashboard | null>(null)
  const [managingStockId, setManagingStockId] = useState<string | null>(null)
  const [stockBatchList, setStockBatchList] = useState<{id: string, cantidad: number, created_at: string}[]>([])
  const [actionLoading, setActionLoading] = useState(false)
  const [showSalesDetail, setShowSalesDetail] = useState(false)
  const [showPriceHistoryModal, setShowPriceHistoryModal] = useState(false)
  const [historyData, setHistoryData] = useState<HistorialPrecio[]>([])

  // ─────────────────────────────────────────────────────────────────────────────
  // UTILIDADES
  // ─────────────────────────────────────────────────────────────────────────────
  const formatMoney = (amount: number | null) =>
    new Intl.NumberFormat('es-AR', { style: 'currency', currency: 'ARS', maximumFractionDigits: 0 }).format(amount || 0)

  // ─────────────────────────────────────────────────────────────────────────────
  // FETCH: Contexto de organización
  // ─────────────────────────────────────────────────────────────────────────────
  const fetchContext = useCallback(async () => {
    const { data: { user } } = await supabase.auth.getUser()
    if(!user) return
    const { data: perfil } = await supabase.from('perfiles').select('organization_id').eq('id', user.id).single()
    if(!perfil?.organization_id) return
    setOrganizationId(perfil.organization_id)

    const { data } = await supabase.from('sucursales').select('id, nombre').eq('organization_id', perfil.organization_id).order('created_at')
    if(data) setSucursales(data)
  }, [])

  useEffect(() => { fetchContext() }, [fetchContext])

  // ─────────────────────────────────────────────────────────────────────────────
  // FETCH: Datos principales
  // ─────────────────────────────────────────────────────────────────────────────
  const fetchData = useCallback(async () => {
    if (!currentSucursalId || !organizationId) return

    // Obtener estadísticas financieras
    const statsResult = await getOwnerStatsAction(
      currentSucursalId,
      dateRange?.from?.toISOString() || '',
      dateRange?.to?.toISOString() || ''
    )

    if (statsResult.success) {
      setTotalVendido(statsResult.totalSold)
      setPaymentBreakdown(statsResult.paymentBreakdown)
      setBiMetrics(statsResult.businessMetrics)
    }

    // Obtener inventario crítico
    const inventoryResult = await getInventoryCriticalAction(currentSucursalId)
    if (inventoryResult.success) {
      // Mapear nuevos tipos a formato local
      setCapitalEnRiesgo({
        capital: inventoryResult.expiringItems.totalValue,
        unidades: inventoryResult.expiringItems.totalUnits,
        criticos: inventoryResult.expiringItems.items.map(item => ({
          id: item.id,
          producto_id: item.productId,
          nombre: item.productName,
          emoji: item.emoji,
          fechaVenc: item.expirationDate,
          cantidad: item.quantity,
          monto: item.valueAtRisk,
        })),
      })
    }

    // Obtener productos con stock desde la nueva vista
    const { data: productsData } = await supabase
      .from('v_products_with_stock')
      .select('*')
      .eq('branch_id', currentSucursalId)
      .eq('is_active', true)

    if (productsData) {
      // Mapear al formato esperado por el dashboard
      const fusion = productsData.map(p => ({
        id: p.id || '',
        nombre: p.name || '',
        categoria: p.category || null,
        precio_venta: Number(p.sale_price) || 0,
        costo: Number(p.cost) || 0,
        emoji: p.emoji || null,
        codigo_barras: p.barcode || null,
        stock_disponible: Number(p.stock_available) || 0,
      }))
      setProductos(fusion)
    }

    // Obtener ventas recientes desde la nueva tabla sales
    let salesQuery = supabase
      .from('sales')
      .select('id, total, payment_method, created_at, notes, sale_items(quantity, unit_price, products(name, emoji))')
      .eq('branch_id', currentSucursalId)

    if (dateRange?.from) salesQuery = salesQuery.gte('created_at', dateRange.from.toISOString())
    if (dateRange?.to) salesQuery = salesQuery.lte('created_at', dateRange.to.toISOString())

    const { data: salesData } = await salesQuery.order('created_at', { ascending: false }).limit(50)

    if (salesData) {
      // Mapear a formato esperado por el dashboard
      const ventasRecientesMaped = salesData.map(s => {
        const items = s.sale_items as unknown as Array<{ quantity: number; unit_price: number; products: { name: string; emoji?: string } | null }> | null
        const firstItem = items && items.length > 0 ? items[0] : null
        return {
          id: s.id,
          fecha_venta: s.created_at,
          metodo_pago: s.payment_method,
          cantidad: items ? items.reduce((sum, item) => sum + (item.quantity || 0), 0) : 0,
          productos: firstItem?.products
            ? { nombre: firstItem.products.name, precio_venta: firstItem.unit_price || 0, emoji: firstItem.products.emoji || '📦' }
            : null,
          notas: s.notes,
        }
      })
      setVentasRecientes(ventasRecientesMaped as VentaJoin[])
    }

    // TODO: Ventas de servicios - por ahora vacío hasta implementar en nuevo schema
    setVentasServicios([])
    setTotalServiciosVendido(0)
    setPaymentBreakdownServicios({ cash: 0, card: 0, transfer: 0, wallet: 0 })

    // Obtener turnos/cajas desde cash_registers
    let cashQuery = supabase
      .from('cash_registers')
      .select('id, date, opening_amount, closing_amount, is_open, opened_at, closed_at, opened_by, memberships(display_name), cash_movements(*), missions(*)')
      .eq('branch_id', currentSucursalId)

    if (dateRange?.from) cashQuery = cashQuery.gte('date', dateRange.from.toISOString().split('T')[0])
    if (dateRange?.to) cashQuery = cashQuery.lte('date', dateRange.to.toISOString().split('T')[0])

    const { data: cashData } = await cashQuery.order('date', { ascending: false })

    if (cashData) {
      // Mapear a formato esperado
      const turnosMaped = cashData.map(c => ({
        id: c.id,
        fecha_apertura: c.opened_at || c.date,
        fecha_cierre: c.closed_at || null,
        monto_inicial: c.opening_amount || 0,
        monto_final: c.closing_amount || null,
        empleado_id: c.opened_by || '',
        sucursal_id: currentSucursalId,
        perfiles: c.memberships ? { nombre: (c.memberships as unknown as { display_name: string }).display_name } : null,
        misiones: Array.isArray(c.missions) ? c.missions.map(m => ({
          id: m.id,
          descripcion: m.description || '',
          es_completada: m.is_completed || false,
          puntos: m.points || 0,
        })) : [],
        movimientos_caja: Array.isArray(c.cash_movements) ? c.cash_movements.map(m => ({
          id: m.id,
          tipo: m.type as 'ingreso' | 'egreso',
          monto: m.amount || 0,
          categoria: m.category || '',
          descripcion: m.description || null,
          created_at: m.created_at,
        })) : [],
      }))
      setTurnosAudit(turnosMaped as TurnoAudit[])
    }

    // Obtener asistencias desde attendance
    let attQuery = supabase
      .from('attendance')
      .select('id, check_in, check_out, user_id, branch_id, memberships(display_name)')
      .eq('branch_id', currentSucursalId)

    if (dateRange?.from) attQuery = attQuery.gte('check_in', dateRange.from.toISOString())
    if (dateRange?.to) attQuery = attQuery.lte('check_in', dateRange.to.toISOString())

    const { data: attData } = await attQuery.order('check_in', { ascending: false }).limit(50)

    if (attData) {
      const asistenciasMaped = attData.map(a => ({
        id: a.id,
        entrada: a.check_in,
        salida: a.check_out || null,
        empleado_id: a.user_id,
        perfiles: a.memberships ? { nombre: (a.memberships as unknown as { display_name: string }).display_name } : null,
        sucursal_id: a.branch_id,
      }))
      setAsistencias(asistenciasMaped as AsistenciaRecord[])
    }
  }, [currentSucursalId, organizationId, dateRange])

  useEffect(() => { setLoading(true); fetchData().finally(() => setLoading(false)) }, [fetchData])

  // ─────────────────────────────────────────────────────────────────────────────
  // MEMO: Datos derivados
  // ─────────────────────────────────────────────────────────────────────────────
  const chartData = useMemo(() => {
    const map: Record<string, number> = {}
    ventasRecientes.slice().reverse().forEach(v => {
      const k = format(parseISO(v.fecha_venta), 'dd/MM')
      map[k] = (map[k] || 0) + (v.precio_venta_historico || v.productos?.precio_venta || 0) * (v.cantidad || 1)
    })
    return Object.entries(map).map(([fecha, total]) => ({ fecha, total }))
  }, [ventasRecientes])

  const dateRangeLabel = useMemo(() => {
    if (!dateRange?.from) return "Filtro de Fecha"
    const from = format(dateRange.from, 'dd/MM', { locale: es })
    if (!dateRange.to || format(dateRange.from, 'yyyy-MM-dd') === format(dateRange.to, 'yyyy-MM-dd')) return `Día: ${from}`
    return `${from} - ${format(dateRange.to, 'dd/MM', { locale: es })}`
  }, [dateRange])

  // ─────────────────────────────────────────────────────────────────────────────
  // HANDLERS
  // ─────────────────────────────────────────────────────────────────────────────
  const handleUpdateProduct = async () => {
    if (!editingProduct) return
    setActionLoading(true)
    try {
      const result = await updateProductAction(editingProduct.id, {
        nombre: editingProduct.nombre,
        precio_venta: editingProduct.precio_venta,
        costo: editingProduct.costo,
        categoria: editingProduct.categoria || '',
        emoji: editingProduct.emoji ?? undefined,
        codigo_barras: editingProduct.codigo_barras ?? undefined,
      })

      if (!result.success) {
        toast.error(result.error || 'Error al actualizar producto')
        return
      }

      toast.success("Producto actualizado")
      setEditingProduct(null)
      fetchData()
    } catch (e: unknown) {
      const errorMessage = e instanceof Error ? e.message : 'Error desconocido'
      toast.error(errorMessage)
    } finally {
      setActionLoading(false)
    }
  }

  const loadPriceHistory = async (pid: string) => {
    setLoading(true)
    const { data } = await supabase.from('historial_precios').select('*, perfiles(nombre)').eq('producto_id', pid).order('fecha_cambio', { ascending: false })
    setHistoryData(data as HistorialPrecio[] || [])
    setShowPriceHistoryModal(true)
    setLoading(false)
  }

  const loadStockBatches = async (pid: string) => {
    setManagingStockId(pid)
    const { data } = await supabase.from('stock').select('id, cantidad, created_at').eq('producto_id', pid).eq('tipo_movimiento', 'entrada').eq('sucursal_id', currentSucursalId).order('created_at', { ascending: false })
    setStockBatchList(data || [])
  }

  const handlePrintTurno = (t: TurnoAudit) => {
    const vT = ventasRecientes.filter(v => {
      const fV = parseISO(v.fecha_venta)
      const fA = parseISO(t.fecha_apertura)
      const fC = t.fecha_cierre ? parseISO(t.fecha_cierre) : new Date()
      return fV >= fA && fV <= fC
    })

    const totE = vT.filter(v => v.metodo_pago === 'efectivo').reduce((acc, curr) => acc + (curr.precio_venta_historico || curr.productos?.precio_venta || 0) * (curr.cantidad || 1), 0)
    const movimientosReales = t.movimientos_caja?.filter(m => m.categoria !== 'ventas') || []
    const gast = movimientosReales.filter(m => m.tipo === 'egreso').reduce((a,b) => a + b.monto, 0)
    const extra = movimientosReales.filter(m => m.tipo === 'ingreso').reduce((a,b) => a + b.monto, 0)
    const esp = t.monto_inicial + totE + extra - gast

    generarTicketPDF({
      empleado: t.perfiles?.nombre || "Empleado",
      fechaApertura: format(parseISO(t.fecha_apertura), 'dd/MM/yyyy HH:mm'),
      fechaCierre: t.fecha_cierre ? format(parseISO(t.fecha_cierre), 'dd/MM/yyyy HH:mm') : null,
      montoInicial: t.monto_inicial,
      totalVentasEfectivo: totE,
      totalIngresos: extra,
      totalGastos: gast,
      cajaEsperada: esp,
      cajaReal: t.monto_final,
      diferencia: t.monto_final !== null ? t.monto_final - esp : null,
      gastos: movimientosReales.map(m => ({
        descripcion: m.descripcion || '',
        monto: m.monto,
        tipo: m.tipo,
        categoria: m.categoria
      }))
    })
    toast.success("Ticket generado")
  }

  // ─────────────────────────────────────────────────────────────────────────────
  // RENDER
  // ─────────────────────────────────────────────────────────────────────────────
  return (
    <div className="min-h-screen bg-slate-50 pb-24">
      {/* Header */}
      <div className="bg-slate-900 text-white p-6 rounded-b-[3rem] shadow-2xl">
        <div className="flex justify-between items-center mb-6">
          <Button variant="ghost" size="icon" onClick={onBack} className="text-white hover:bg-white/10">
            <ArrowLeft className="h-6 w-6" />
          </Button>
          <div className="flex items-center gap-3">
            <div className="flex items-center gap-2 bg-white/10 rounded-full px-4 py-1.5 border border-white/10 backdrop-blur-md">
              <MapPin className="h-3.5 w-3.5 text-blue-400" />
              <Select value={currentSucursalId} onValueChange={setCurrentSucursalId}>
                <SelectTrigger className="h-7 w-[150px] border-0 bg-transparent p-0 text-xs font-bold focus:ring-0">
                  <SelectValue placeholder="Sucursal" />
                </SelectTrigger>
                <SelectContent>
                  {sucursales.map(s => <SelectItem key={s.id} value={s.id}>{s.nombre}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>
            <Dialog>
              <Button variant="ghost" size="icon" className="h-9 w-9 rounded-full bg-white/5 hover:bg-white/20">
                <Settings className="h-4 w-4" />
              </Button>
              <DialogContent className="sm:max-w-lg">
                <DialogHeader><DialogTitle>Configuración de Sucursales</DialogTitle></DialogHeader>
                <GestionSucursales onUpdate={fetchContext} />
              </DialogContent>
            </Dialog>
          </div>
        </div>
        <div className="flex justify-between items-end">
          <div>
            <h1 className="text-2xl font-black tracking-tight flex items-center gap-2 uppercase">
              Torre de Control <Sparkles className="h-5 w-5 text-yellow-400" />
            </h1>
            <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest">Panel Administrativo Global</p>
          </div>
          <CapitalBadges organizationId={organizationId} formatMoney={formatMoney} />
        </div>

        {/* Tabs */}
        <div className="flex gap-2 mt-8 overflow-x-auto pb-2 scrollbar-hide">
          {[
            { id: "sales", label: "Caja y Ventas", icon: DollarSign },
            { id: "inventory", label: "Stock", icon: Package },
            { id: "finance", label: "Panel de Utilidades", icon: TrendingUp },
            { id: "supervision", label: "Supervisión 360°", icon: Eye },
            { id: "catalog", label: "Alta de Catálogo", icon: Plus },
            { id: "suppliers", label: "Proveedores", icon: Users },
            { id: "team", label: "Mi Equipo", icon: Briefcase },
            { id: "alerts", label: "Advertencias de Stock", icon: AlertTriangle },
          ].map(t => (
            <Button
              key={t.id}
              onClick={() => setActiveTab(t.id as DashboardTab)}
              variant={activeTab === t.id ? "secondary" : "ghost"}
              size="sm"
              className="rounded-full text-xs font-bold whitespace-nowrap"
            >
              <t.icon className="mr-1.5 h-3.5 w-3.5" /> {t.label}
            </Button>
          ))}
        </div>
      </div>

      {/* Content */}
      <div className="p-4 space-y-4">
        {/* Date Filter */}
        {["sales", "supervision", "finance"].includes(activeTab) && (
          <Popover>
            <PopoverTrigger asChild>
              <Button variant="outline" className="w-full justify-start h-14 border-2 shadow-sm bg-white font-black text-slate-700">
                <CalendarIcon className="mr-2 h-5 w-5 text-primary" /> {dateRangeLabel.toUpperCase()}
              </Button>
            </PopoverTrigger>
            <PopoverContent className="w-auto p-0" align="center">
              <Calendar mode="range" selected={dateRange} onSelect={setDateRange} locale={es} />
            </PopoverContent>
          </Popover>
        )}

        {/* Tab Content */}
        {activeTab === "sales" && (
          <TabSales
            sucursalId={currentSucursalId}
            organizationId={organizationId}
            formatMoney={formatMoney}
            onRefresh={fetchData}
            totalVendido={totalVendido}
            totalServiciosVendido={totalServiciosVendido}
            paymentBreakdown={paymentBreakdown}
            paymentBreakdownServicios={paymentBreakdownServicios}
            ventasRecientes={ventasRecientes}
            ventasServicios={ventasServicios}
            chartData={chartData}
            onShowSalesDetail={() => setShowSalesDetail(true)}
          />
        )}

        {activeTab === "alerts" && (
          <TabAlerts
            sucursalId={currentSucursalId}
            organizationId={organizationId}
            formatMoney={formatMoney}
            onRefresh={fetchData}
            capitalEnRiesgo={capitalEnRiesgo}
            productos={productos}
            umbralStockBajo={UMBRAL_STOCK_BAJO}
          />
        )}

        {activeTab === "supervision" && (
          <TabSupervision
            sucursalId={currentSucursalId}
            organizationId={organizationId}
            formatMoney={formatMoney}
            onRefresh={fetchData}
            turnosAudit={turnosAudit}
            asistencias={asistencias}
            ventasRecientes={ventasRecientes}
            onPrintTurno={handlePrintTurno}
          />
        )}

        {activeTab === "finance" && (
          <TabFinance
            sucursalId={currentSucursalId}
            organizationId={organizationId}
            formatMoney={formatMoney}
            onRefresh={fetchData}
            biMetrics={biMetrics}
          />
        )}

        {activeTab === "inventory" && (
          <TabInventory
            sucursalId={currentSucursalId}
            organizationId={organizationId}
            formatMoney={formatMoney}
            onRefresh={fetchData}
            productos={productos}
            searchQuery={searchQuery}
            onSearchChange={setSearchQuery}
            loading={loading}
            umbralStockBajo={UMBRAL_STOCK_BAJO}
            onEditProduct={setEditingProduct}
            onLoadPriceHistory={loadPriceHistory}
            onLoadStockBatches={loadStockBatches}
          />
        )}

        {activeTab === "catalog" && (
          <CrearProducto sucursalId={currentSucursalId} onProductCreated={() => { setActiveTab("inventory"); fetchData(); }} />
        )}

        {activeTab === "suppliers" && (
          <div className="space-y-6 animate-in fade-in">
            <ControlSaldoProveedor />
            <GestionProveedores sucursalId={currentSucursalId} organizationId={organizationId} />
          </div>
        )}

        {activeTab === "team" && (
          <div className="space-y-6 animate-in fade-in">
            <TeamRanking />
            <InvitarEmpleado />
            <Card className="p-6 border-2">
              <h3 className="text-lg font-black text-slate-800 uppercase mb-4 flex items-center gap-2">
                <QrCode className="h-5 w-5 text-blue-600" /> Generar QR de Fichaje
              </h3>
              <p className="text-sm text-slate-600 mb-4">
                Genera códigos QR para que tus empleados puedan fichar entrada y salida escaneando el código del local.
              </p>
              <GenerarQRFichaje />
            </Card>
          </div>
        )}
      </div>

      {/* Modal: Editar Producto */}
      <Dialog open={!!editingProduct} onOpenChange={o => !o && setEditingProduct(null)}>
        <DialogContent className="max-w-md rounded-3xl">
          <DialogHeader>
            <DialogTitle className="font-black uppercase flex items-center gap-2">
              <Pencil className="h-5 w-5 text-primary"/> Editar Catálogo
            </DialogTitle>
          </DialogHeader>
          {editingProduct && (
            <div className="space-y-6 py-4">
              <div className="grid grid-cols-4 gap-3">
                <div className="col-span-1">
                  <Label className="text-[10px] font-black uppercase">Icono</Label>
                  <Input value={editingProduct.emoji ?? ""} onChange={e => setEditingProduct({...editingProduct, emoji: e.target.value})} className="text-center text-3xl h-16 rounded-2xl bg-slate-50" />
                </div>
                <div className="col-span-3">
                  <Label className="text-[10px] font-black uppercase">Nombre</Label>
                  <Input value={editingProduct.nombre} onChange={e => setEditingProduct({...editingProduct, nombre: e.target.value})} className="h-16 font-bold rounded-2xl" />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label className="text-[10px] font-black uppercase text-slate-400">Costo</Label>
                  <Input type="number" value={editingProduct.costo} onChange={e => setEditingProduct({...editingProduct, costo: parseFloat(e.target.value)})} className="rounded-xl h-12" />
                </div>
                <div>
                  <Label className="text-[10px] font-black uppercase text-primary">Precio</Label>
                  <Input type="number" value={editingProduct.precio_venta} onChange={e => setEditingProduct({...editingProduct, precio_venta: parseFloat(e.target.value)})} className="border-primary/40 font-black h-12 rounded-xl text-lg" />
                </div>
              </div>
              <Button onClick={handleUpdateProduct} disabled={actionLoading} className="w-full h-14 font-black text-lg rounded-2xl shadow-lg">
                {actionLoading ? <Loader2 className="animate-spin"/> : "GUARDAR CAMBIOS"}
              </Button>
              <Button
                variant="ghost"
                className="w-full text-red-500 text-[10px] font-black"
                onClick={async () => {
                  if(confirm("¿Eliminar?")){
                    const result = await deleteProductAction(editingProduct.id)
                    if (result.success) {
                      toast.success("Producto eliminado")
                      fetchData()
                      setEditingProduct(null)
                    } else {
                      toast.error(result.error || 'Error al eliminar producto')
                    }
                  }
                }}
              >
                ELIMINAR PRODUCTO
              </Button>
            </div>
          )}
        </DialogContent>
      </Dialog>

      {/* Modal: Historial de Precios */}
      <Dialog open={showPriceHistoryModal} onOpenChange={setShowPriceHistoryModal}>
        <DialogContent className="max-h-[80vh] overflow-y-auto rounded-3xl">
          <DialogHeader>
            <DialogTitle className="font-black uppercase tracking-tighter flex items-center gap-2">
              <Clock className="h-5 w-5 text-primary"/> Historial Precios
            </DialogTitle>
          </DialogHeader>
          <div className="space-y-3 mt-4">
            {historyData.map((h, i) => (
              <div key={i} className="p-4 border-l-4 border-primary bg-slate-50 rounded-xl relative">
                <div className="flex justify-between items-start mb-3">
                  <p className="font-black text-slate-900 text-xs uppercase">{format(parseISO(h.fecha_cambio), 'dd MMM yyyy')}</p>
                  <p className="text-[9px] font-black text-slate-400">{format(parseISO(h.fecha_cambio), 'HH:mm')} HS</p>
                </div>
                <div className="grid grid-cols-2 gap-6">
                  <div>
                    <p className="text-[9px] font-black uppercase">Venta</p>
                    <p className="text-lg font-black text-primary">{formatMoney(h.precio_venta_nuevo)}</p>
                  </div>
                  <div>
                    <p className="text-[9px] font-black uppercase">Costo</p>
                    <p className="text-lg font-black text-slate-900">{formatMoney(h.costo_nuevo)}</p>
                  </div>
                </div>
                <div className="mt-3 pt-3 border-t flex items-center gap-1.5">
                  <span className="text-[9px] font-black text-slate-400 uppercase">Autor: {h.perfiles?.nombre || 'Admin'}</span>
                </div>
              </div>
            ))}
          </div>
        </DialogContent>
      </Dialog>

      {/* Modal: Lotes de Stock */}
      <Dialog open={!!managingStockId} onOpenChange={o => !o && setManagingStockId(null)}>
        <DialogContent className="rounded-3xl">
          <DialogHeader>
            <DialogTitle className="font-black uppercase flex items-center gap-2">
              <History className="h-5 w-5 text-orange-500"/> Lotes Locales
            </DialogTitle>
          </DialogHeader>
          <div className="space-y-3 max-h-[500px] overflow-y-auto pr-2 mt-4">
            {stockBatchList.map(b => (
              <div key={b.id} className="flex justify-between items-center p-4 bg-slate-50 rounded-2xl border-2 border-slate-100 hover:border-orange-200">
                <div className="space-y-1">
                  <p className="font-black text-xs">CANT: {b.cantidad} u.</p>
                  <p className="text-[10px] font-bold text-slate-400 uppercase">Ingreso: {format(parseISO(b.created_at), 'dd/MM/yy HH:mm')} hs</p>
                </div>
                <Button
                  variant="ghost"
                  size="icon"
                  className="text-red-400 hover:bg-red-50 rounded-full"
                  onClick={async () => {
                    if(confirm("¿Eliminar lote?")){
                      await supabase.from('stock').delete().eq('id', b.id)
                      fetchData()
                      setManagingStockId(null)
                    }
                  }}
                >
                  <Trash2 className="h-5 w-5"/>
                </Button>
              </div>
            ))}
          </div>
        </DialogContent>
      </Dialog>

      {/* Modal: Detalle de Ventas */}
      <Dialog open={showSalesDetail} onOpenChange={setShowSalesDetail}>
        <DialogContent className="max-w-2xl max-h-[85vh] flex flex-col rounded-3xl">
          <DialogHeader className="border-b pb-4">
            <DialogTitle className="font-black uppercase tracking-widest text-slate-800 flex items-center gap-2">
              <Receipt className="h-6 w-6 text-primary"/> Libro de Ventas
            </DialogTitle>
          </DialogHeader>
          <div className="flex-1 overflow-y-auto pr-3 space-y-3 mt-6">
            {ventasRecientes.map(v => (
              <div key={v.id} className="flex justify-between items-center p-4 bg-white border-2 rounded-2xl shadow-sm">
                <div className="flex items-center gap-4">
                  <span className="text-3xl bg-slate-100 w-12 h-12 flex items-center justify-center rounded-xl">{v.productos?.emoji}</span>
                  <div>
                    <p className="font-black uppercase text-slate-800 text-sm leading-none mb-1">{v.productos?.nombre}</p>
                    <p className="text-[10px] font-bold text-slate-400 uppercase">{format(parseISO(v.fecha_venta), 'HH:mm')} hs • {v.metodo_pago?.replace('_',' ')}</p>
                    {v.notas && <p className="text-[10px] font-black text-indigo-600 mt-1 italic tracking-tighter">💬 {v.notas}</p>}
                  </div>
                </div>
                <div className="text-right">
                  <p className="font-black text-emerald-600 text-lg leading-none mb-0.5">{formatMoney((v.precio_venta_historico || v.productos?.precio_venta || 0) * (v.cantidad || 1))}</p>
                  <p className="text-[10px] font-black text-slate-400 uppercase">{v.cantidad || 1} U.</p>
                </div>
              </div>
            ))}
          </div>
          <DialogFooter className="border-t pt-4">
            <Button variant="outline" className="w-full font-black text-[11px] h-12 rounded-2xl uppercase tracking-widest" onClick={() => setShowSalesDetail(false)}>
              Cerrar Auditoría
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  )
}
